				for i, item in x256217_var_LiujinId do
							local equip	=	GetEquipItemCountByLess(varMap, varPlayer, 1,4,item)
							local bag	=	GetBagItemCountByLess(varMap, varPlayer, 1,4,item)  --0--升星 1--打孔 2--宝石
							if equip >= 1 or bag >=1 then
						
							local varQuestIdx = GetQuestIndexByID(varMap,varPlayer,x256217_var_QuestId6)                                                  
	    				SetQuestByIndex(varMap,varPlayer,varQuestIdx,0,1)
	    				SetQuestByIndex(varMap,varPlayer,varQuestIdx,7,1)
	    				break
					end
				end
	 	end

	
end

